function pad(number) { return String(number).padStart(2, '0'); }
function dateKey(date) { return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`; }
function parseDate(key) {
  const [year, month, date] = key.split('-').map(Number);
  return new Date(year, month - 1, date);
}
function isValidDateKey(key) {
  if (!/^\d{4}-\d{2}-\d{2}$/.test(key || '')) return false;
  return dateKey(parseDate(key)) === key;
}
function readableDate(key) {
  const date = parseDate(key);
  return `${date.getFullYear()} 年 ${date.getMonth() + 1} 月 ${date.getDate()} 日`;
}

function escapeHtml(value) {
  return String(value).replace(/[&<>'"]/g, (character) => ({
    '&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;'
  })[character]);
}

const today = new Date();
const todayKey = dateKey(today);
const initialDay = days[todayKey] ? todayKey : Object.keys(days).sort().at(-1);
const state = {
  day: initialDay,
  view: 'overview',
  lens: 'all',
  memberQuery: '',
  calendarMonth: new Date(parseDate(initialDay).getFullYear(), parseDate(initialDay).getMonth(), 1)
};
